void ProcessDialogEvent(){	ref NPChar;	aref Link, NextDiag;	DeleteAttribute(&Dialog, "Links");	makeref(NPChar, CharacterRef);	makearef(Link, Dialog.Links);	makearef(NextDiag, NPChar.Dialog);	switch (Dialog.CurrentNode)	{		case "first time":			dialog.text = StringFromKey("sailor3_1");			link.l1 = StringFromKey("sailor3_2");			link.l1.go = "1";		break;		case "1":			GiveItem2Character(pchar, "FQ_letter8");			AddMoneyToCharacter(pchar, -5);			dialog.text = StringFromKey("sailor3_3");			link.l1 = StringFromKey("sailor3_4");			link.l1.go = "exit";		break;		case "exit":			if (CheckAttribute(NextDiag, "TempNode")) NextDiag.CurrentNode = NextDiag.TempNode;			DialogExit();		break;	}}